function hrd_sd_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('hrd_sd');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'year' => Request::val('year', '2020-21'),
		'Candidate_Type' => Request::val('Candidate_Type', ''),
		'Title_of_the_Program' => Request::val('Title_of_the_Program', ''),
		'Total_Number_of_Beneficiaries' => Request::val('Total_Number_of_Beneficiaries', ''),
		'Number_of_Women_Beneficiaries' => Request::val('Number_of_Women_Beneficiaries', ''),
		'Total_Number_of_SC_Beneficiaries' => Request::val('Total_Number_of_SC_Beneficiaries', ''),
		'Total_Number_of_ST_Beneficiaries' => Request::val('Total_Number_of_ST_Beneficiaries', ''),
		'category' => Request::val('category', ''),
		'Start_Date' => Request::dateComponents('Start_Date', ''),
		'End_Date' => Request::dateComponents('End_Date', ''),
		'Collaborating_Organisation' => Request::val('Collaborating_Organisation', ''),
		'Outcomes' => Request::val('Outcomes', ''),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('hrd_sd', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		hrd_sd_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function hrd_sd_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);
	$currentUsername = getLoggedMemberID();
	$errorMessage = '';

	// launch requests, asynchronously
	curl_batch($requests);
}

function hrd_sd_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('hrd_sd', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: hrd_sd_before_delete
	if(function_exists('hrd_sd_before_delete')) {
		$args = [];
		if(!hrd_sd_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	sql("DELETE FROM `hrd_sd` WHERE `id`='{$selected_id}'", $eo);

	// hook: hrd_sd_after_delete
	if(function_exists('hrd_sd_after_delete')) {
		$args = [];
		hrd_sd_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='hrd_sd' AND `pkValue`='{$selected_id}'", $eo);
}

function hrd_sd_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('hrd_sd', $selected_id, 'edit')) return false;

	$data = [
		'year' => Request::val('year', ''),
		'Candidate_Type' => Request::val('Candidate_Type', ''),
		'Title_of_the_Program' => Request::val('Title_of_the_Program', ''),
		'Total_Number_of_Beneficiaries' => Request::val('Total_Number_of_Beneficiaries', ''),
		'Number_of_Women_Beneficiaries' => Request::val('Number_of_Women_Beneficiaries', ''),
		'Total_Number_of_SC_Beneficiaries' => Request::val('Total_Number_of_SC_Beneficiaries', ''),
		'Total_Number_of_ST_Beneficiaries' => Request::val('Total_Number_of_ST_Beneficiaries', ''),
		'category' => Request::val('category', ''),
		'Start_Date' => Request::dateComponents('Start_Date', ''),
		'End_Date' => Request::dateComponents('End_Date', ''),
		'Collaborating_Organisation' => Request::val('Collaborating_Organisation', ''),
		'Outcomes' => Request::val('Outcomes', ''),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
	];

	if($data['year'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'Year': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	// get existing values
	$old_data = getRecord('hrd_sd', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: hrd_sd_before_update
	if(function_exists('hrd_sd_before_update')) {
		$args = ['old_data' => $old_data];
		if(!hrd_sd_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'hrd_sd',
		backtick_keys_once($set),
		['`id`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="hrd_sd_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}


	update_calc_fields('hrd_sd', $data['selectedID'], calculated_fields()['hrd_sd']);

	// hook: hrd_sd_after_update
	if(function_exists('hrd_sd_after_update')) {
		if($row = getRecord('hrd_sd', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['id'];
		$args = ['old_data' => $old_data];
		if(!hrd_sd_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('hrd_sd', $selected_id);
}

